// HasGuests applies the HasEdge predicate on the "guests" edge.
func HasGuests() predicate.RoomBooking {
	return predicate.RoomBooking(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, GuestsTable, GuestsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasGuestsWith applies the HasEdge predicate on the "guests" edge with a given conditions (other predicates).
func HasGuestsWith(preds ...predicate.RoomGuest) predicate.RoomBooking {
	return predicate.RoomBooking(func(s *sql.Selector) {
		step := newGuestsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RoomBooking) predicate.RoomBooking {
	return predicate.RoomBooking(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RoomBooking) predicate.RoomBooking {
	return predicate.RoomBooking(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RoomBooking) predicate.RoomBooking {
	return predicate.RoomBooking(sql.NotPredicates(p))
}
